package com.vikinghelmet.dnd.dpr

import com.vikinghelmet.dnd.dpr.character.Character
import com.vikinghelmet.dnd.dpr.monsters.Monster
import com.vikinghelmet.dnd.dpr.spells.Spell
import kotlinx.serialization.json.Json
import okhttp3.OkHttpClient
import okhttp3.Request
import java.io.File
import java.io.IOException
import java.io.InputStream

class App {
    val greeting: String
        get() {
            return "Hello World!"
        }
}

val spells = ArrayList<Spell>()
val monsters = ArrayList<Monster>()
val attacks = ArrayList<Attack>()
var character: Character ?= null

fun calculateSpellDPR(attack: Attack) {
    val monster = getMonster(attack.monster)
    if (monster == null) {
        println("monster not found: "+attack.monster)
        return
    }

    val spell = getSpell(attack.spell)
    if (spell == null) {
        println("spell not found: "+attack.spell)
        return
    }

    val dpr = DamagePerRound(character!!)

    dpr.calculateSpellDPR (spell, attack, monster)
    println ("")
}

fun getMonster(name: String): Monster? {
    if (monsters.isEmpty()) return null

    for (monster in monsters) {
        if (monster.name == name) {
            return monster
        }
    }
    return null
}

fun getSpell(name: String): Spell? {
    if (spells.isEmpty()) return null

    for (spell in spells) {
        if (spell.name == name) {
            return spell
        }
    }
    return null
}

fun getRequest(url: String): String? {
    val client = OkHttpClient() // TODO move?
    val request = Request.Builder().url(url).build()

    val response = client.newCall(request).execute()
    if (response.code >= 400) {
        throw IOException("request failed, response code = "+response.code)
    }
    return response.body?.string() ?: "{}"
}

fun getFileOrURL(fileOrUrl: String): String? {
    return if (fileOrUrl.startsWith("http")) {
        getRequest(fileOrUrl)
    }
    else {
        File(fileOrUrl).readText()
    }
}

fun getCharacter(arg: String): Character? {
    if (!arg.contains(":")) return null
    val id = arg.split(":")[1]
    val charJson = getFileOrURL("https://character-service.dndbeyond.com/character/v5/character/"+id) ?: "{}"
    //println ("charJson = "+charJson)
    return Json.decodeFromString(charJson)
}

fun dump(arg: String) {
    if (!arg.contains(":")) {
        for (item in spells)    println(Json.encodeToString(item))
        for (item in monsters)  println(Json.encodeToString(item))
        for (item in attacks)   println(Json.encodeToString(item))
        println(Json.encodeToString(character))
        return
    }

    val dumpType = arg.split(":")[1]
    when (dumpType) {
        "spells" -> {
            for (item in spells)  println(Json.encodeToString(item))
        }
        "monsters" -> {
            for (item in monsters)  println(Json.encodeToString(item))
        }
        "attacks" -> {
            for (item in attacks)  println(Json.encodeToString(item))
        }
        "character" -> {
            println(Json.encodeToString(character))
        }
    }
}

fun search(arg: String) {
    val searchType = arg.split(":")[1]
    val searchValue = arg.split(":")[2]
    when (searchType) {
        "spells" -> {
            for (item in spells) if (item.name.contains(searchValue))  println(Json.encodeToString(item))
        }
        "monsters" -> {
            for (item in monsters) if (item.name.contains(searchValue))  println(Json.encodeToString(item))
        }
        "attacks" -> {
//            for (item in attacks) if (item.name.contains(searchValue))  println(Json.encodeToString(item))
        }
    }
}

fun getResource(fileName: String): String? {
    val inputStream: InputStream = object {}.javaClass.getResourceAsStream("/$fileName") ?: return null
    try {
        return inputStream.bufferedReader().use { it.readText() }
    } catch (e: Exception) {
        e.printStackTrace()
        return null
    }
}

fun main(args : Array<String>) {
    var exitEarly = false

    if (args.isEmpty()) {
        System.err.println()
        System.err.println("Usage:  [file.json ...]  [character]  < dump[:opt] | search<opt> | attacks.json >");
        System.err.println()
        System.err.println("File options:")
        System.err.println()
        System.err.println("\t file.json \t load spell or monster data from the given file; this is optional: program is prepackaged with 2024 data")
        System.err.println()
        System.err.println("Character options:")
        System.err.println()
        System.err.println("\t NumericID \t read character from DND Beyond API (character must have public visibility)")
        System.err.println("\t file.json \t read character from a file")
        System.err.println()
        System.err.println("Dump (debug) options:")
        System.err.println()
        System.err.println("\t dump:spells \t export all known spells");
        System.err.println("\t dump:monsters \t export all known monsters");
        System.err.println("\t dump:attacks \t export attacks from user input");
        System.err.println("\t dump:character\t export (minimal) character data from DND Beyond");
        System.err.println("\t dump \t\t export all of the above");
        System.err.println()
        System.err.println("Search commands:")
        System.err.println()
        System.err.println("\t search:spells:NAME \t search for name in list of spells, and display details if found");
        System.err.println("\t search:monsters:NAME \t search for name in list of spells, and display details if found");
        System.err.println()
        System.err.println("Attacks")
        System.err.println()
        System.err.println("\t json file: should contain an array of monster/spell pairs, for example:")
        System.err.println()
        System.err.println("\t\t [{\"monster\":\"Goblin\",\"spell\":\"Ensnaring Strike\"}]\n")
        System.err.println()
        System.err.println("\t ")
        System.err.println("""Note: for more complex scenarios, the attack json also supports preconditions.  For example:
            
    [
        {
            "monster": "Goblin",
            "spell": "Ensnaring Strike",
            "preconditions": {
                "bonusDiceToSave":       { "d4": 1, "d6": 0, "d8": 0, "d10": 0, "d12": 0 },
                "penaltyDiceToSave":     { "d4": 0, "d6": 0, "d8": 0, "d10": 0, "d12": 0 },
                "bonusDamageOnFirstHit": { "d4": 0, "d6": 0, "d8": 0, "d10": 0, "d12": 0 },
                "bonusDamage": 0
            }
        }
    ]            
        """)
        System.err.println()
    }

    val spellResource = getResource("spells.json")
    if (spellResource != null)  spells.addAll(Json.decodeFromString(spellResource))

    val monsterResource = getResource("monsters.json")
    if (monsterResource != null)  monsters.addAll(Json.decodeFromString(monsterResource))

    // each arg should be a json file (spells, monsters, character, or attacks) or a debug cmd (dump, search, test)
    for (arg in args) {
        if (arg.endsWith(".json")) {
            val jsonString = getFileOrURL(arg)
            if (jsonString == null) {
                println("unable to read input: $arg")
            }
            else if (jsonString.contains("School")) {
                spells.addAll(Json.decodeFromString(jsonString))
            }
            else if (jsonString.contains("\"Monsters\"")){
                monsters.addAll(Json.decodeFromString(jsonString))
            }
            else if (jsonString.contains("\"monster\"")) {
                attacks.addAll(Json.decodeFromString(jsonString))
            }
            else if (jsonString.contains("\"username\"")) {
                character = Json.decodeFromString(jsonString)
            }
        }
        else if (arg.endsWith(".json")){
            println("unknown file type: $arg")
        }
        else if (arg.startsWith("character")) {
            character = getCharacter(arg)
        }
        else if (arg.startsWith("dump")) {
            dump(arg)
            exitEarly = true
        }
        else if (arg.startsWith("search")) {
            search(arg)
            exitEarly = true
        }
        else if (arg.startsWith("test")) {
            character?.test()
            exitEarly = true
        }
    }

    if (exitEarly) {
        // quietly go away
    }
    else if (spells.isEmpty()) {
        println("no spell data")
    }
    else if (monsters.isEmpty()) {
        println("no monsters data")
    }
    else if (character == null) {
        println("no character data")
    }
    else if (attacks.isEmpty()) {
        println("no attacks specified")
    }
    else {
        for (attack in attacks) {
            calculateSpellDPR(attack)
        }
    }
}
